public class Main {
    public static int fib(int n) {
        System.out.println("fib(" + n + ") called");
        if (n <= 1) return n;
        return fib(n - 1) + fib(n - 2);
    }

    public static void main(String[] args) {
        int result = fib(4);
        System.out.println("Result: " + result);
    }
}

